import{_ as e,c as a,o as i,a5 as n}from"./chunks/framework.CgT1UzWm.js";const k=JSON.parse('{"title":"RETURNS Annotation","titleTemplate":"NpgsqlRest","description":"Skip the PostgreSQL Describe step and resolve return columns from a composite type. Enables SQL files that use runtime-created temp tables.","frontmatter":{"outline":[2,3],"title":"RETURNS Annotation","titleTemplate":"NpgsqlRest","description":"Skip the PostgreSQL Describe step and resolve return columns from a composite type. Enables SQL files that use runtime-created temp tables.","head":[["meta",{"name":"keywords","content":"npgsqlrest returns annotation, composite type override, skip describe, temp table sql file, do block result"}],["meta",{"property":"og:title","content":"NpgsqlRest RETURNS Annotation"}],["meta",{"property":"og:description","content":"Skip the PostgreSQL Describe step and resolve return columns from a composite type."}],["meta",{"property":"og:type","content":"article"}]]},"headers":[],"relativePath":"annotations/returns.md","filePath":"annotations/returns.md"}'),t={name:"annotations/returns.md"};function l(p,s,r,h,o,d){return i(),a("div",null,s[0]||(s[0]=[n(`<h1 id="returns" tabindex="-1">RETURNS <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;RETURNS&quot;">​</a></h1><p>Skip the PostgreSQL Describe step for a statement and resolve return columns from a composite type instead. This is a positional annotation — it applies to the next statement below it.</p><p>Available since version 3.12.0.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@returns &lt;composite_type_name&gt;</span></span>
<span class="line"><span>@returns &lt;scalar_type&gt;</span></span>
<span class="line"><span>@returns void</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>Supported values:</p><ul><li><strong>Composite type name</strong> — schema-qualified (e.g., <code>public.my_type</code>) or unqualified (e.g., <code>my_type</code>). Columns resolved from the type definition.</li><li><strong>Scalar type</strong> — any built-in PostgreSQL type (e.g., <code>integer</code>, <code>text</code>, <code>boolean</code>, <code>jsonb</code>). Declares a single-column result. Only the first column from the query is used at runtime.</li><li><strong><code>void</code></strong> — no columns, no results.</li></ul><p><strong>This annotation skips the PostgreSQL Describe step entirely for the annotated statement.</strong> The statement&#39;s SQL is never sent to PostgreSQL during startup.</p><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><ul><li><strong>Composite types:</strong> when the statement references objects that don&#39;t exist at startup (e.g., temp tables created inside DO blocks)</li><li><strong>Scalar types:</strong> when you want to declare a single typed return value and ignore extra columns</li><li><strong><code>void</code>:</strong> when the statement returns no results (e.g., <code>INSERT</code>, <code>CREATE TEMP TABLE</code>, <code>set_config</code>)</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $1 val1 text</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $2 val2 integer</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">begin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> set_config(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app.val1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, true); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @skip</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> set_config(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app.val2&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, true); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @skip</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">do $$ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">begin</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    create</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> temp </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">on</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> commit</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> drop</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> as</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> current_setting(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app.val1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> val1,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">           current_setting(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app.val2&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> val2,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">           true </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> active;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; $$;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @returns my_result_type</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @result data</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @single</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _result;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div></details><p>Where <code>my_result_type</code> is defined as:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> my_result_type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    val1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    val2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">integer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    active </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">boolean</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>Without <code>@returns</code>, the <code>select * from _result</code> statement fails at startup because the temp table doesn&#39;t exist yet. With <code>@returns my_result_type</code>, the columns are resolved from the composite type definition in <code>pg_catalog</code>.</p><h3 id="scalar-type" tabindex="-1">Scalar Type <a class="header-anchor" href="#scalar-type" aria-label="Permalink to &quot;Scalar Type&quot;">​</a></h3><p>Declare a single typed column. Only the first column from the query is used at runtime — extra columns are ignored:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @returns integer</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>Returns: <code>[42]</code></p><p>With <code>@single</code>, returns a bare scalar value:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @returns integer</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @single</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>Returns: <code>42</code></p><p>Supported scalar types: <code>integer</code>, <code>text</code>, <code>boolean</code>, <code>jsonb</code>, <code>json</code>, <code>bigint</code>, <code>numeric</code>, <code>real</code>, <code>double precision</code>, <code>date</code>, <code>timestamp</code>, <code>timestamptz</code>, <code>uuid</code>, <code>bytea</code>, and all other built-in PostgreSQL types.</p><h3 id="void-statements" tabindex="-1">Void Statements <a class="header-anchor" href="#void-statements" aria-label="Permalink to &quot;Void Statements&quot;">​</a></h3><p>Use <code>@returns void</code> to skip Describe for statements that return no results:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- HTTP POST</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $1 key text</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $2 value text</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @returns void</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> set_config($</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, false);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @result data</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> current_setting($</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, true) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> result;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><p>The first statement&#39;s Describe is skipped entirely. In multi-command files, it produces a rows-affected count in the response. For single-command files, it makes the endpoint void (returns 204 No Content).</p><h2 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h2><ul><li><strong>The Describe step is skipped entirely</strong> for annotated statements — the SQL is never sent to PostgreSQL during startup</li><li>For composite types: the type must exist in the database at startup. If not found, an error is logged and the file is skipped or exits (depending on <code>ErrorMode</code>)</li><li>For <code>void</code>: the statement is treated as returning no columns (zero-column result)</li><li>No parameter type inference happens for the skipped statement — other statements in the same multi-command file provide parameter types</li><li>At runtime, the actual query result must match the declared type&#39;s column structure — mismatches may produce incorrect output</li><li>Can be combined with other positional annotations like <code>@result</code>, <code>@single</code>, <code>@skip</code></li></ul><div class="tip custom-block"><p class="custom-block-title">@returns void vs @void</p><p>For single-command SQL files, <code>@returns void</code> has the same runtime effect as <a href="./void.html"><code>@void</code></a> — both return 204 No Content. The difference: <code>@returns void</code> <strong>skips the Describe step</strong> (the SQL is never sent to PostgreSQL at startup), while <code>@void</code> still runs Describe and only changes the runtime response. Use <code>@returns void</code> when the statement would fail Describe (e.g., references a temp table). Use <code>@void</code> when Describe succeeds but you don&#39;t want any response.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../guide/annotations.html">Comment Annotations Guide</a> - How annotations work</li><li><a href="./result-name.html">RESULT_NAME</a> - Rename result keys in multi-command files</li><li><a href="./single.html">SINGLE</a> - Return single records as objects</li><li><a href="./void.html">VOID</a> - Force void response</li><li><a href="./../config/sql-file-source.html">SQL File Source</a> - SQL file source configuration</li></ul>`,32)]))}const u=e(t,[["render",l]]);export{k as __pageData,u as default};
